// src/contexts/ProductContext.tsx
import React, { createContext, useContext, useState, useEffect } from "react";

export interface ProductHistoryEntry {
    date: string;    // ISO string (e.g. "2025-05-16")
    price: number;
    stock: number;
}

export interface Product {
    id: number;
    name: string;
    category: string;
    stock: number;
    weight: number;
    price: number;
    threshold: number;
    description?: string;
    createdAt: string;              // ISO string
    history: ProductHistoryEntry[]; // chronological, newest last
}

interface ProductContextType {
    products: Product[];
    addProduct: (p: Omit<Product, "id" | "threshold" | "history">) => void;
    updateProduct: (
        id: number,
        updates: Omit<Product, "id" | "threshold" | "history">
    ) => void;
    updateProductPriceAndStock: (
        id: number,
        newPrice: number,
        newStock: number,
        date: string
    ) => void;
    deleteProduct: (id: number) => void;
}

const ProductContext = createContext<ProductContextType | undefined>(undefined);

export const ProductsProvider: React.FC<{ children: React.ReactNode }> = ({
                                                                              children,
                                                                          }) => {
    const STORAGE_KEY = "inventory";
    const [products, setProducts] = useState<Product[]>(() => {
        const stored = localStorage.getItem(STORAGE_KEY);
        return stored ? JSON.parse(stored) : [];
    });

    // Sync to localStorage on every change
    useEffect(() => {
        localStorage.setItem(STORAGE_KEY, JSON.stringify(products));
    }, [products]);

    const addProduct = (
        newProd: Omit<Product, "id" | "threshold" | "history">
    ) => {
        const id = products.length ? Math.max(...products.map((p) => p.id)) + 1 : 1;
        const threshold = newProd.stock;
        const history: ProductHistoryEntry[] = [
            { date: newProd.createdAt, price: newProd.price, stock: newProd.stock },
        ];
        const product: Product = { ...newProd, id, threshold, history };
        setProducts((prev) => [...prev, product]);
    };

    const updateProduct = (
        id: number,
        updates: Omit<Product, "id" | "threshold" | "history">
    ) => {
        setProducts((prev) =>
            prev.map((p) => {
                if (p.id !== id) return p;
                // Update first history entry date if createdAt changed
                const newHistory = [...p.history];
                newHistory[0] = {
                    date: updates.createdAt,
                    price: updates.price,
                    stock: updates.stock,
                };
                return {
                    ...p,
                    ...updates,
                    threshold: updates.stock,
                    history: newHistory,
                };
            })
        );
    };

    const updateProductPriceAndStock = (
        id: number,
        newPrice: number,
        newStock: number,
        date: string
    ) => {
        setProducts((prev) =>
            prev.map((p) => {
                if (p.id !== id) return p;
                const entry: ProductHistoryEntry = {
                    date,
                    price: newPrice,
                    stock: newStock,
                };
                return {
                    ...p,
                    price: newPrice,
                    stock: newStock,
                    threshold: p.threshold,
                    history: [...p.history, entry],
                };
            })
        );
    };

    const deleteProduct = (id: number) => {
        setProducts((prev) => prev.filter((p) => p.id !== id));
    };

    return (
        <ProductContext.Provider
            value={{
                products,
                addProduct,
                updateProduct,
                updateProductPriceAndStock,
                deleteProduct,
            }}
        >
            {children}
        </ProductContext.Provider>
    );
};

export function useProducts() {
    const ctx = useContext(ProductContext);
    if (!ctx) {
        throw new Error("useProducts must be used within a ProductsProvider");
    }
    return ctx;
}
